INSERT INTO "pengumuman" ("id_pengumuman", "judul", "isi", "tanggal_pengumuman", "id_batch", "id_user", "createdAt", "updatedAt") VALUES
(1, 'Pembukaan Asistensi Batch 2024', '<p>Selamat datang para asisten Batch 2024. Asistensi resmi dimulai tanggal 1 Februari 2024.</p>', '2024-02-01 08:00:00', 1, 2, '2024-02-01 08:00:00', '2024-02-01 08:00:00'),
(2, 'Jadwal Minggu Pertama Batch 2024', '<p>Minggu pertama fokus pada instalasi dasar dan pengenalan lingkungan Linux.</p>', '2024-02-05 07:30:00', 1, 2, '2024-02-05 07:30:00', '2024-02-05 07:30:00'),
(3, 'Reminder Pengumpulan Laporan Khusus', '<p>Bagi peserta yang namanya tercantum, mohon segera kumpulkan laporan susulan.</p>', '2024-05-10 09:00:00', 1, 4, '2024-05-10 09:00:00', '2024-05-10 09:00:00'),
(4, 'Pembukaan Asistensi Batch 2025', '<p>Selamat datang di Batch 2025. Silakan cek jadwal asistensi di portal masing-masing.</p>', '2025-02-01 08:00:00', 2, 3, '2025-02-01 08:00:00', '2025-02-01 08:00:00'),
(5, 'Pembagian Kelompok Batch 2025', '<p>Pembagian kelompok telah dilakukan. Cek halaman profil untuk melihat kelompok Anda.</p>', '2025-02-06 10:00:00', 2, 3, '2025-02-06 10:00:00', '2025-02-06 10:00:00'),
(6, 'Deadline Laporan Akhir Batch 2025', '<p>Deadline pengumpulan laporan akhir adalah 25 Agustus 2025 pukul 23.59 WIB.</p>', '2025-07-20 08:00:00', 2, 5, '2025-07-20 08:00:00', '2025-07-20 08:00:00');
